1	export type Item = {
2	  kind: "sword" | "amulet" | "staff" | "potion" | "rune" | "moonstone";
3	  cursed?: boolean;
4	  enchantment?: number;
5	};
6	
7	export type QuoteStep = { kind: "quote"; items: Item[] };
8	
9	export type Scenario = {
10	  customer: { yearsWithMHPCO: number };
11	  steps: QuoteStep[];
12	};
13	
14	export type ScenarioResult = {
15	  results: unknown[];
16	};
17	
18	const COMPONENT_BASE_PREMIUM = 25;
19	
20	const BASE_PREMIUM_BY_ITEM: Record<Item["kind"], number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: COMPONENT_BASE_PREMIUM,
26	  moonstone: COMPONENT_BASE_PREMIUM,
27	};
28	
29	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
30	const PROCESSING_FEE = 5;
31	
32	const CURSED_SURCHARGE_RATE = 0.5;
33	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
34	const HIGH_ENCHANTMENT_THRESHOLD = 5;
35	
36	function isCursed(item: Item): boolean {
37	  return item.cursed === true;
38	}
39	
40	function isHighlyEnchanted(item: Item): boolean {
41	  return (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
42	}
43	
44	function riskMultiplierForItem(item: Item): number {
45	  return (
46	    1 +
47	    (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
48	    (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0)
49	  );
50	}
51	
52	function basePremiumForItem(item: Item): number {
53	  return BASE_PREMIUM_BY_ITEM[item.kind] * riskMultiplierForItem(item);
54	}
55	
56	type QuoteResult = { kind: "quote"; premium: number };
57	
58	const BUILDING_BLOCK_BASE_PREMIUM = 60;
59	const BUILDING_BLOCK_SIZE = 3;
60	const COMPONENT_KINDS: ReadonlyArray<Item["kind"]> = ["rune", "moonstone"];
61	
62	type ItemGroup = { kind: Item["kind"]; items: Item[] };
63	
64	function groupByKind(items: Item[]): ItemGroup[] {
65	  const groups = new Map<Item["kind"], Item[]>();
66	  for (const item of items) {
67	    const group = groups.get(item.kind) ?? [];
68	    group.push(item);
69	    groups.set(item.kind, group);
70	  }
71	  return Array.from(groups, ([kind, items]) => ({ kind, items }));
72	}
73	
74	function isBuildingBlock(group: ItemGroup): boolean {
75	  return group.items.length === BUILDING_BLOCK_SIZE && COMPONENT_KINDS.includes(group.kind);
76	}
77	
78	function basePremiumForGroup(group: ItemGroup): number {
79	  if (isBuildingBlock(group)) {
80	    return BUILDING_BLOCK_BASE_PREMIUM;
81	  }
82	  return group.items.reduce((sum, item) => sum + basePremiumForItem(item), 0);
83	}
84	
85	function basePremiumForItems(items: Item[]): number {
86	  return groupByKind(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
87	}
88	
89	function quoteStep(step: QuoteStep): QuoteResult {
90	  const basePremium = basePremiumForItems(step.items);
91	  const surcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
92	  const premium = Math.ceil(basePremium + surcharge + PROCESSING_FEE);
93	  return { kind: "quote", premium };
94	}
95	
96	export function processScenario(scenario: Scenario): ScenarioResult {
97	  const results = scenario.steps.map(quoteStep);
98	  return { results };
99	}
